<template><div class="workbench-page"><section class="welcome-banner"><div><span class="eyebrow">TODAY'S CLINIC</span><h1>{{greeting}}，{{doctorName}}</h1><p>{{fullDate}} · 今日诊疗工作已为您准备就绪</p></div><div class="banner-time"><span>当前时间</span><strong>{{currentTime}}</strong><small>门诊服务进行中</small></div></section><section class="stats-grid"><article class="stat-card teal"><div class="stat-icon"><el-icon><UserFilled /></el-icon></div><div><span>今日患者</span><strong>{{registrations.length}}</strong><small>今日挂号总人数</small></div><i></i></article><article class="stat-card amber"><div class="stat-icon"><el-icon><Clock /></el-icon></div><div><span>待就诊</span><strong>{{statusCount('待就诊')}}</strong><small>等待叫号与接诊</small></div><i></i></article><article class="stat-card blue"><div class="stat-icon"><el-icon><FirstAidKit /></el-icon></div><div><span>就诊中</span><strong>{{statusCount('就诊中')}}</strong><small>正在进行诊疗</small></div><i></i></article><article class="stat-card green"><div class="stat-icon"><el-icon><CircleCheckFilled /></el-icon></div><div><span>已完成</span><strong>{{statusCount('已就诊')}}</strong><small>今日完成诊疗</small></div><i></i></article></section><section class="queue-card"><div class="queue-header"><div><span class="section-kicker">PATIENT QUEUE</span><h2>今日患者队列</h2><p>按挂号时间查看并处理今日诊疗任务</p></div><div class="queue-actions"><el-input v-model="keyword" placeholder="搜索患者姓名" clearable :prefix-icon="Search"/><el-select v-model="statusFilter" placeholder="全部状态" clearable><el-option v-for="s in statuses" :key="s" :label="s" :value="s"/></el-select><el-button class="refresh-btn" :icon="Refresh" @click="loadData" :loading="loading">刷新</el-button></div></div><div class="queue-summary"><div><span class="live-dot"></span> 实时诊疗队列</div><span>共 {{filteredList.length}} 位患者</span></div><el-table :data="filteredList" v-loading="loading" class="patient-table" :header-cell-style="tableHeaderStyle"><el-table-column label="患者信息" min-width="190"><template #default="{row}"><div class="patient-cell"><div class="patient-avatar">{{row.patientName?.slice(0,1)}}</div><div><strong>{{row.patientName}}</strong><span>预约号 YN{{String(row.id).padStart(6,'0')}}</span></div></div></template></el-table-column><el-table-column label="就诊安排" min-width="170"><template #default="{row}"><div class="schedule-cell"><strong>{{row.registrationDate}}</strong><span><el-icon><Clock /></el-icon>{{row.timeSlot}}门诊</span></div></template></el-table-column><el-table-column prop="departmentName" label="科室" min-width="130"/><el-table-column label="当前状态" width="120"><template #default="{row}"><span class="status-pill" :class="statusClass(row.status)"><i></i>{{row.status}}</span></template></el-table-column><el-table-column label="挂号时间" min-width="165"><template #default="{row}"><span class="muted-time">{{formatTime(row.createTime)}}</span></template></el-table-column><el-table-column label="诊疗操作" width="160" fixed="right"><template #default="{row}"><el-button v-if="row.status==='待就诊'" class="action-primary" size="small" :loading="row._loading" @click="handleStart(row)">开始看诊 <el-icon><ArrowRight /></el-icon></el-button><el-button v-else-if="row.status==='就诊中'" class="action-success" size="small" @click="goConsultation(row)">继续看诊 <el-icon><ArrowRight /></el-icon></el-button><el-button v-else-if="row.status==='已就诊'" class="action-ghost" size="small" @click="goConsultation(row)">查看详情</el-button><span v-else class="cancel-text">已取消</span></template></el-table-column><template #empty><div class="custom-empty"><div><el-icon><User /></el-icon></div><strong>暂无匹配患者</strong><span>当前筛选条件下没有诊疗任务</span></div></template></el-table></section></div></template>
<script setup>import{ref,computed,onMounted,onUnmounted}from'vue';import{useRouter}from'vue-router';import{ElMessage}from'element-plus';import{Refresh,Search}from'@element-plus/icons-vue';import{getTodayRegistrations,startConsultation}from'../../api/doctor';const router=useRouter(),loading=ref(false),registrations=ref([]),keyword=ref(''),statusFilter=ref(''),currentTime=ref(''),statuses=['待就诊','就诊中','已就诊','已取消'];const info=JSON.parse(localStorage.getItem('doctorInfo')||'{}'),doctorName=info.name||'医生';const hour=new Date().getHours(),greeting=hour<11?'早上好':hour<14?'中午好':hour<18?'下午好':'晚上好';const fullDate=new Date().toLocaleDateString('zh-CN',{year:'numeric',month:'long',day:'numeric',weekday:'long'});let timer;const updateTime=()=>currentTime.value=new Date().toLocaleTimeString('zh-CN',{hour:'2-digit',minute:'2-digit'});onMounted(()=>{loadData();updateTime();timer=setInterval(updateTime,30000)});onUnmounted(()=>clearInterval(timer));const statusCount=s=>registrations.value.filter(r=>r.status===s).length;const filteredList=computed(()=>registrations.value.filter(r=>(!statusFilter.value||r.status===statusFilter.value)&&(!keyword.value||r.patientName?.includes(keyword.value.trim()))));const statusClass=s=>({'待就诊':'waiting','就诊中':'active','已就诊':'done','已取消':'cancelled'}[s]||'');const formatTime=t=>t?new Date(t).toLocaleString('zh-CN'):'--';const tableHeaderStyle={background:'#f7fafb',color:'#6f858d',fontSize:'12px',fontWeight:'650',height:'48px'};const loadData=async()=>{loading.value=true;try{const r=await getTodayRegistrations();registrations.value=r.data||[]}finally{loading.value=false}};const handleStart=async row=>{row._loading=true;try{await startConsultation(row.id);ElMessage.success('已开始看诊');row.status='就诊中';router.push(`/consultation/${row.id}`)}finally{row._loading=false}};const goConsultation=row=>router.push(`/consultation/${row.id}`)</script>
<style scoped>.workbench-page{padding:2px}.welcome-banner{position:relative;overflow:hidden;display:flex;align-items:center;justify-content:space-between;min-height:145px;padding:28px 34px;border-radius:22px;background:linear-gradient(125deg,#073b5c,#087a7c 64%,#1ba08f);color:#fff;box-shadow:0 16px 38px rgba(11,74,89,.15)}.welcome-banner:after{content:'';position:absolute;right:-70px;top:-145px;width:310px;height:310px;border:1px solid rgba(255,255,255,.12);border-radius:50%;box-shadow:0 0 0 55px rgba(255,255,255,.03)}.welcome-banner>div{position:relative;z-index:1}.eyebrow,.section-kicker{font-size:10px;font-weight:750;letter-spacing:2.2px;opacity:.65}.welcome-banner h1{margin:8px 0 7px;font-size:27px}.welcome-banner p{color:rgba(255,255,255,.65);font-size:12px}.banner-time{min-width:155px;padding:15px 19px;border:1px solid rgba(255,255,255,.16);border-radius:16px;background:rgba(255,255,255,.1);backdrop-filter:blur(8px)}.banner-time span,.banner-time strong,.banner-time small{display:block}.banner-time span{color:rgba(255,255,255,.58);font-size:9px}.banner-time strong{margin:4px 0;font-size:25px}.banner-time small{color:#86ecd7;font-size:9px}.stats-grid{display:grid;grid-template-columns:repeat(4,1fr);gap:16px;margin:20px 0}.stat-card{position:relative;overflow:hidden;display:flex;align-items:center;gap:14px;min-height:112px;padding:20px;border:1px solid #e3edef;border-radius:18px;background:#fff;box-shadow:0 8px 25px rgba(26,67,81,.06)}.stat-card>i{position:absolute;right:-28px;bottom:-34px;width:85px;height:85px;border-radius:50%;background:var(--soft)}.stat-icon{width:46px;height:46px;display:flex;align-items:center;justify-content:center;border-radius:14px;background:var(--soft);color:var(--accent);font-size:21px}.stat-card span,.stat-card strong,.stat-card small{display:block}.stat-card span{color:#82949b;font-size:11px}.stat-card strong{margin:4px 0 1px;color:#24434f;font-size:26px}.stat-card small{color:#a4b0b5;font-size:9px}.teal{--soft:#e5f6f3;--accent:#0b9283}.amber{--soft:#fff3df;--accent:#dc8a28}.blue{--soft:#e8f0ff;--accent:#5279c4}.green{--soft:#e7f7ed;--accent:#2b9a68}.queue-card{overflow:hidden;border:1px solid #e1ebed;border-radius:20px;background:#fff;box-shadow:0 10px 30px rgba(26,67,81,.07)}.queue-header{display:flex;align-items:flex-end;justify-content:space-between;gap:20px;padding:24px 26px 20px}.section-kicker{color:#108b80}.queue-header h2{margin:5px 0 4px;font-size:19px}.queue-header p{color:#9aa8ad;font-size:10px}.queue-actions{display:flex;gap:9px}.queue-actions .el-input{width:185px}.queue-actions .el-select{width:125px}.queue-actions :deep(.el-input__wrapper),.queue-actions :deep(.el-select__wrapper){border-radius:10px;box-shadow:0 0 0 1px #dfe8ea inset}.refresh-btn{border-radius:10px;color:#087f84}.queue-summary{display:flex;justify-content:space-between;padding:11px 26px;border-top:1px solid #edf2f3;border-bottom:1px solid #edf2f3;background:#f8fbfb;color:#85979e;font-size:10px}.live-dot{display:inline-block;width:7px;height:7px;margin-right:5px;border-radius:50%;background:#22bb80;box-shadow:0 0 0 4px rgba(34,187,128,.1)}.patient-table:deep(.el-table__inner-wrapper:before){display:none}.patient-cell{display:flex;align-items:center;gap:11px}.patient-avatar{width:38px;height:38px;display:flex;align-items:center;justify-content:center;border-radius:12px;background:linear-gradient(145deg,#dcefee,#bee0dc);color:#087f84;font-weight:750}.patient-cell strong,.patient-cell span,.schedule-cell strong,.schedule-cell span{display:block}.patient-cell strong{font-size:13px}.patient-cell span{margin-top:3px;color:#9aa9ae;font-size:9px}.schedule-cell strong{font-size:12px}.schedule-cell span{display:flex;align-items:center;gap:4px;margin-top:4px;color:#8b9da4;font-size:10px}.status-pill{display:inline-flex;align-items:center;gap:6px;padding:6px 10px;border-radius:15px;font-size:10px;font-weight:650}.status-pill i{width:6px;height:6px;border-radius:50%;background:currentColor}.waiting{background:#fff3df;color:#c97819}.active{background:#e8f0ff;color:#5074ba}.done{background:#e6f7ed;color:#218c60}.cancelled{background:#fff0f0;color:#cb5b5b}.muted-time{color:#82969d;font-size:10px}.action-primary,.action-success,.action-ghost{border-radius:9px}.action-primary{border:0;background:linear-gradient(135deg,#087f84,#18a18f);color:#fff}.action-success{border-color:#9bd8c6;background:#edf9f5;color:#178a6c}.action-ghost{border-color:#dce7e9;color:#55727b}.cancel-text{color:#a7b2b6;font-size:10px}.custom-empty{display:flex;flex-direction:column;align-items:center;padding:50px}.custom-empty>div{width:52px;height:52px;display:flex;align-items:center;justify-content:center;border-radius:17px;background:#edf4f5;color:#80a0a3;font-size:22px}.custom-empty strong{margin-top:12px;color:#526c75}.custom-empty span{margin-top:5px;color:#a2afb3;font-size:10px}@media(max-width:1100px){.stats-grid{grid-template-columns:repeat(2,1fr)}.queue-header{align-items:flex-start;flex-direction:column}.queue-actions{width:100%}}@media(max-width:700px){.welcome-banner{padding:24px}.banner-time{display:none}.stats-grid{grid-template-columns:1fr}.queue-actions{flex-wrap:wrap}.queue-actions .el-input{width:100%}}</style>
